class BatchProcessor:
    def __init__(self, batch_size):
        self.batch_size = batch_size
        self.queue = []
        self.batches_sent = 0

    def add(self, item):
        self.queue.append(item)
        if len(self.queue) >= self.batch_size:
            return self.flush()
        return None

    def flush(self):
        if not self.queue:
            return None
        batch = self.queue[:self.batch_size]
        self.queue = self.queue[self.batch_size:]
        self.batches_sent += 1
        return batch

    def get_stats(self):
        return {'queued': len(self.queue), 'sent': self.batches_sent}

