class HealthAggregator:
    def __init__(self):
        self.services = {}

    def register(self, name, check_func):
        self.services[name] = check_func

    def check_all(self):
        results = {}
        overall = True
        for name, check in self.services.items():
            try:
                healthy = check()
                results[name] = 'healthy' if healthy else 'unhealthy'
                if not healthy:
                    overall = False
            except Exception as e:
                results[name] = f'error: {e}'
                overall = False
        return {'overall': 'healthy' if overall else 'unhealthy', 'services': results}

