import hashlib

class FeatureFlags:
    def __init__(self, config):
        self.config = config

    def is_enabled(self, flag_name, user_id=None):
        flag = self.config.get(flag_name)
        if not flag:
            return False

        if flag.get('enabled') == False:
            return False

        # Check user targeting
        target_users = flag.get('target_users', [])
        if user_id and user_id in target_users:
            return True

        # Percentage rollout
        rollout = flag.get('rollout_percent', 0)
        if user_id:
            # Deterministic based on user_id
            hash_val = int(hashlib.md5(f'{flag_name}:{user_id}'.encode()).hexdigest(), 16)
            user_bucket = hash_val % 100
            return user_bucket < rollout

        return rollout >= 100

