class EventStore:
    def __init__(self):
        self.events = []

    def append(self, event_type, data):
        self.events.append({'type': event_type, 'data': data})

    def get_events(self):
        return self.events.copy()

    def get_state(self):
        balance = 0
        for e in self.events:
            if e['type'] == 'deposit':
                balance += e['data']['amount']
            elif e['type'] == 'withdrawal':
                balance -= e['data']['amount']
        return {'balance': balance, 'transaction_count': len(self.events)}

