class Node:
    def __init__(self, node_id):
        self.node_id = node_id
        self.is_leader = False
        self.alive = True

    def elect(self, all_nodes):
        higher_nodes = [n for n in all_nodes if n.node_id > self.node_id and n.alive]
        if not higher_nodes:
            self.is_leader = True
            return True
        return False

class Cluster:
    def __init__(self, node_ids):
        self.nodes = {nid: Node(nid) for nid in node_ids}
        self.leader = None

    def run_election(self):
        for nid in sorted(self.nodes.keys(), reverse=True):
            node = self.nodes[nid]
            if node.alive and node.elect(list(self.nodes.values())):
                self.leader = nid
                break
        return self.leader

    def fail_node(self, node_id):
        if node_id in self.nodes:
            self.nodes[node_id].alive = False
            self.nodes[node_id].is_leader = False
            if self.leader == node_id:
                self.leader = None

# Test
