leader2 = cluster.run_election()
print(f'After failure: {leader2}')

class IdempotentProcessor:
    def __init__(self):
        self.processed_keys = set()
        self.results = {}
        self.call_count = 0

    def process(self, idempotency_key, operation):
        self.call_count += 1

        if idempotency_key in self.processed_keys:
            return {'status': 'duplicate', 'result': self.results[idempotency_key]}

        # Process
        result = operation()
        self.processed_keys.add(idempotency_key)
        self.results[idempotency_key] = result
        return {'status': 'processed', 'result': result}

    def get_stats(self):
        return {
            'unique_keys': len(self.processed_keys),
            'total_calls': self.call_count,
            'deduplicated': self.call_count - len(self.processed_keys)
        }

# Test
